 17→function preferredMimeType(): string {
 18→  if (typeof MediaRecorder !== 'undefined') {
 19→    if (MediaRecorder.isTypeSupported('audio/webm')) return 'audio/webm'
 20→    if (MediaRecorder.isTypeSupported('audio/mp4')) return 'audio/mp4'
