 33→  const streamRef = useRef<MediaStream | null>(null)
 34→  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null)
 35→
 36→  const clearTimer = useCallback(() => {
 37→    if (intervalRef.current !== null) {
 38→      clearInterval(intervalRef.current)
 39→      intervalRef.current = null
 40→    }
 41→  }, [])
 42→
 43→  const releaseStream = useCallback(() => {
 44→    if (streamRef.current) {
 45→      streamRef.current.getTracks().forEach((t) => t.stop())
 46→      streamRef.current = null
 47→    }
 48→  }, [])
 49→
 50→  const start = useCallback(async () => {
 51→    setError(null)
 52→    setAudioBlob(null)
 53→    setDuration(0)
 54→    chunksRef.current = []
 55→
 56→    try {
 57→      const stream = await navigator.mediaDevices.getUserMedia({ audio: true })
 58→      streamRef.current = stream
 59→
 60→      const mimeType = preferredMimeType()
 61→      const recorder = mimeType
 62→        ? new MediaRecorder(stream, { mimeType })
 63→        : new MediaRecorder(stream)
 64→
 65→      recorder.ondataavailable = (e) => {
 66→        if (e.data.size > 0) {
 67→          chunksRef.current.push(e.data)
 68→        }
 69→      }
 70→
 71→      recorder.onstop = () => {
 72→        const type = recorder.mimeType || 'audio/webm'
 73→        const blob = new Blob(chunksRef.current, { type })
 74→        setAudioBlob(blob)
 75→        setStatus('stopped')
 76→        clearTimer()
 77→        releaseStream()
 78→      }
 79→
 80→      recorderRef.current = recorder
 81→      recorder.start()
 82→      setStatus('recording')
 83→
 84→      intervalRef.current = setInterval(() => {
 85→        setDuration((d) => d + 1)
 86→      }, 1000)
 87→    } catch (err) {
 88→      releaseStream()
 89→      if (err instanceof DOMException) {
 90→        if (err.name === 'NotAllowedError') {
 91→          setError('Microphone permission denied')
 92→        } else if (err.name === 'NotFoundError') {
 93→          setError('No microphone found')
 94→        } else {
 95→          setError(`Microphone error: ${err.message}`)
 96→        }
 97→      } else {
 98→        setError('Failed to start recording')
 99→      }
100→    }
101→  }, [clearTimer, releaseStream])
102→
103→  const stop = useCallback(() => {
104→    if (recorderRef.current && recorderRef.current.state !== 'inactive') {
105→      recorderRef.current.stop()
106→    }
107→  }, [])
108→
109→  const pause = useCallback(() => {
110→    if (recorderRef.current && recorderRef.current.state === 'recording') {
111→      recorderRef.current.pause()
112→      clearTimer()
113→      setStatus('paused')
114→    }
115→  }, [clearTimer])
116→
117→  const resume = useCallback(() => {
118→    if (recorderRef.current && recorderRef.current.state === 'paused') {
119→      recorderRef.current.resume()
120→      setStatus('recording')
121→      intervalRef.current = setInterval(() => {
122→        setDuration((d) => d + 1)
123→      }, 1000)
124→    }
125→  }, [])
126→
127→  const reset = useCallback(() => {
128→    if (recorderRef.current && recorderRef.current.state !== 'inactive') {
129→      recorderRef.current.stop()
130→    }
131→    clearTimer()
132→    releaseStream()
133→    recorderRef.current = null
134→    chunksRef.current = []
135→    setAudioBlob(null)
136→    setDuration(0)
137→    setError(null)
138→    setStatus('idle')
139→  }, [clearTimer, releaseStream])
140→
141→  useEffect(() => {
142→    return () => {
143→      clearTimer()
144→      releaseStream()
145→      if (recorderRef.current && recorderRef.current.state !== 'inactive') {
146→        recorderRef.current.stop()
147→      }
148→    }
149→  }, [clearTimer, releaseStream])
150→
151→  return { status, audioBlob, duration, error, start, stop, pause, resume, reset }
152→}
