266→// Search is the resolver for the search field.
267→func (r *queryResolver) Search(ctx context.Context, query string, filter *model.ItemFilter, limit *int, threshold *float64) (*model.SearchResult, error) {
268→	claims, err := requireAuth(ctx)
269→	if err != nil {
270→		return nil, err
271→	}
272→
273→	th := derefFloat64Or(threshold, 0.0)
274→	lim := derefIntOr(limit, 20)
275→	f := toItemFilter(filter)
276→
277→	// Use semantic search when threshold > 0 and embedder is available
278→	if th > 0 && r.Embedder != nil && query != "" {
279→		embedding, err := r.Embedder.Embed(ctx, query)
280→		if err != nil {
281→			slog.ErrorContext(ctx, "resolver: search: embedding failed, falling back to FTS",
282→				"error", err,
283→			)
284→		} else {
285→			result, err := r.ItemService.SemanticSearch(ctx, claims.UserID, embedding, f, lim, th)
286→			if err != nil {
287→				return nil, fmt.Errorf("resolver: semantic search: %w", err)
288→			}
289→			return &model.SearchResult{
290→				Items:   toGraphQLItems(result.Items),
291→				Total:   result.Total,
292→				HasMore: result.HasMore,
293→			}, nil
294→		}
295→	}
296→
297→	// Fall back to full-text search
298→	result, err := r.ItemService.Search(ctx, claims.UserID, query, f, lim, th)
299→	if err != nil {
300→		return nil, fmt.Errorf("resolver: search: %w", err)
301→	}
302→
303→	return &model.SearchResult{
304→		Items:   toGraphQLItems(result.Items),
305→		Total:   result.Total,
306→		HasMore: result.HasMore,
307→	}, nil
308→}
