 95→// Search performs full-text search over items using the search_vector column.
 96→func (s *Service) Search(ctx context.Context, ownerID uuid.UUID, query string, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
 97→	if query == "" {
 98→		return &SearchResult{Items: []*Item{}}, nil
 99→	}
100→	limit = clampLimit(limit, maxLimit)
101→
102→	qb := &queryBuilder{}
103→	qb.add("owner_id = $%d", ownerID)
104→	qb.add("search_vector @@ plainto_tsquery('english', $%d)", query)
105→	applyFilter(qb, filter)
106→	whereClause := qb.where()
107→
108→	// Count total matches
109→	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
110→	var total int
111→	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
112→		return nil, fmt.Errorf("item: search count: %w", err)
113→	}
114→
115→	dataQuery := fmt.Sprintf(
116→		`SELECT %s FROM items %s ORDER BY ts_rank(search_vector, plainto_tsquery('english', $2)) DESC LIMIT $%d`,
117→		itemColumns, whereClause, qb.nextParam())
118→	qb.args = append(qb.args, limit)
119→
120→	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
121→	if err != nil {
122→		return nil, fmt.Errorf("item: search query: %w", err)
123→	}
124→	defer rows.Close()
125→
126→	items, err := scanItems(rows)
127→	if err != nil {
128→		return nil, fmt.Errorf("item: search scan: %w", err)
129→	}
130→
131→	return &SearchResult{
132→		Items:   items,
133→		Total:   total,
134→		HasMore: len(items) < total,
135→	}, nil
136→}
