 3→import (
 4→	"fmt"
 5→	"strings"
 6→
 7→	"github.com/google/uuid"
 8→)
 9→
10→// KeyFor generates the S3 key for an item's content.
11→// Pattern: {owner_id}/{type}/{item_id}/{filename}
12→func KeyFor(ownerID uuid.UUID, itemType string, itemID uuid.UUID, filename string) string {
13→	return fmt.Sprintf("%s/%s/%s/%s", ownerID, itemType, itemID, filename)
14→}
15→
16→// BookmarkKey returns the key for a bookmark's fetched HTML content.
17→func BookmarkKey(ownerID, itemID uuid.UUID) string {
18→	return KeyFor(ownerID, "bookmarks", itemID, "content.html")
19→}
20→
21→// AudioKey returns the key for a voice note's audio file.
22→func AudioKey(ownerID, itemID uuid.UUID, format string) string {
23→	return KeyFor(ownerID, "voice_notes", itemID, "audio."+format)
24→}
25→
26→// FileKey returns the key for a generic file upload.
27→func FileKey(ownerID, itemID uuid.UUID, filename string) string {
28→	return KeyFor(ownerID, "files", itemID, filename)
29→}
30→
31→// ValidateKeyOwnership checks that an S3 key belongs to the given owner.
32→// Keys must start with "{ownerID}/" and must not contain path traversal sequences.
33→func ValidateKeyOwnership(key string, ownerID uuid.UUID) error {
34→	if key == "" {
35→		return fmt.Errorf("storage: key is empty")
36→	}
37→	if strings.Contains(key, "..") {
38→		return fmt.Errorf("storage: key contains path traversal")
39→	}
40→	prefix := ownerID.String() + "/"
41→	if !strings.HasPrefix(key, prefix) {
42→		return fmt.Errorf("storage: key does not belong to owner")
43→	}
44→	// Must have content after the owner prefix (at least "type/file")
45→	rest := key[len(prefix):]
46→	if rest == "" || !strings.Contains(rest, "/") {
47→		return fmt.Errorf("storage: key has invalid structure")
48→	}
49→	return nil
50→}
